Rule.Source:
 	
  import sailpoint.object.*;
  import sailpoint.api.*;
  import org.apache.log4j.Logger;

  Logger logger = Logger.getLogger("rule.Ascension.fodLocation.TriggerEmail1");

  String KEY_ESCALATION_WG_NAME = "PeopleSoft Attestation Escalations Workgroup";
  logger.debug("#############################Rule - PeopleSoft Attestation Escalation Start##########################");
  logger.debug("#############################item.getRemindersSent(): " + item.getRemindersSent());
  logger.debug("#############################item.getEscalationCount(): " + item.getEscalationCount());
  logger.debug("#############################item.toXml(): " + item.toXml());
  Identity escalationWG = context.getObjectByName(Identity.class, KEY_ESCALATION_WG_NAME);
  Identity owner = item.getNotificationOwner(context);
  
  if( owner != null  && KEY_ESCALATION_WG_NAME.equals(owner.getName()))
  {
    logger.debug("#############################Rule - PeopleSoft Attestation Escalation end 0##########################");
    return null;
  }

  if (item.getEscalationCount()> 0 || owner == null || owner.getManager() == null)
  {
    logger.debug("#############################Rule - PeopleSoft Attestation Escalation end 1##########################");
    return escalationWG.getName();
  }
  logger.debug("#############################Rule - PeopleSoft Attestation Escalation end 2 ##########################");
  return owner.getManager().getName();
